-- Nutrition: macro targets, meal planning + logging, and a recipe library.

-- ============================================================
-- 1. Recipe library (public, seeded)
-- ============================================================
create table if not exists public.recipes (
  id uuid primary key default gen_random_uuid(),
  slug text unique not null,
  title text not null,
  category text not null,
  image_url text,
  description text,
  calories int not null default 0,
  protein_g int not null default 0,
  carbs_g int not null default 0,
  fat_g int not null default 0,
  servings int not null default 1,
  prep_minutes int not null default 15,
  tags text[] not null default '{}',
  ingredients text[] not null default '{}',
  steps text[] not null default '{}',
  created_at timestamptz not null default now()
);
create index if not exists recipes_category_idx on public.recipes (category);

alter table public.recipes enable row level security;
drop policy if exists "anyone signed in reads recipes" on public.recipes;
create policy "anyone signed in reads recipes" on public.recipes
  for select to authenticated using (true);

-- ============================================================
-- 2. Daily macro targets (auto-suggested, user-editable)
-- ============================================================
create table if not exists public.nutrition_targets (
  user_id uuid primary key references auth.users (id) on delete cascade,
  calories int not null default 2200,
  protein_g int not null default 160,
  carbs_g int not null default 220,
  fat_g int not null default 70,
  updated_at timestamptz not null default now()
);
alter table public.nutrition_targets enable row level security;
drop policy if exists "own nutrition targets" on public.nutrition_targets;
create policy "own nutrition targets" on public.nutrition_targets
  for all to authenticated using (user_id = auth.uid()) with check (user_id = auth.uid());

-- ============================================================
-- 3. Meal entries (a planned/eaten item on a day + meal slot)
-- ============================================================
create table if not exists public.meal_entries (
  id uuid primary key default gen_random_uuid(),
  user_id uuid not null references auth.users (id) on delete cascade,
  entry_date date not null default current_date,
  meal text not null default 'breakfast' check (meal in ('breakfast','lunch','dinner','snack')),
  recipe_id uuid references public.recipes (id) on delete set null,
  title text not null,
  calories int not null default 0,
  protein_g int not null default 0,
  carbs_g int not null default 0,
  fat_g int not null default 0,
  servings numeric(4,2) not null default 1,
  created_at timestamptz not null default now()
);
create index if not exists meal_entries_user_date_idx
  on public.meal_entries (user_id, entry_date);
alter table public.meal_entries enable row level security;
drop policy if exists "own meal entries" on public.meal_entries;
create policy "own meal entries" on public.meal_entries
  for all to authenticated using (user_id = auth.uid()) with check (user_id = auth.uid());

-- ============================================================
-- 4. Seed the recipe library
-- ============================================================
on conflict (slug) do nothing;
